class Solution:
    def canFormArray(self, arr, pieces):
        by_head = {p[0]: p for p in pieces}
        i, n = 0, len(arr)
        while i < n:
            piece = by_head.get(arr[i])
            if piece is None:
                return False
            for v in piece:
                if i >= n or arr[i] != v:
                    return False
                i += 1
        return True

