var canFormArray = function(arr, pieces) {
    const byHead = new Map();
    for (const p of pieces) byHead.set(p[0], p);
    let i = 0;
    const n = arr.length;
    while (i < n) {
        const piece = byHead.get(arr[i]);
        if (!piece) return false;
        for (const v of piece) {
            if (i >= n || arr[i] !== v) return false;
            i++;
        }
    }
    return true;
};
